import { Layout, ListPlus, ChartArea, Users, Settings } from 'lucide-react';
import { Link, useLocation } from 'react-router-dom';
//import logo from './logo.svg';

export default function Sidebar() {
  const location = useLocation();

  return (
    <div className="w-64 bg-white shadow-sm relative">
      <div className="p-4 flex items-center">
        <div>
          {/* <img src={logo} alt="Logo" className="w-8 h-8" /> */}
        </div>
        <span className="ml-2 text-xl font-bold text-gray-800">Tracking</span>
      </div>

      <div className="mt-6">
        <div className="px-4 py-2 text-xs font-semibold text-gray-500 uppercase">Management</div>

        <Link
          to="/dashboard"
          className={`flex items-center w-full px-4 py-3 ${
            location.pathname === '/dashboard' ? 'bg-blue-800 text-white' : 'text-gray-700'
          }`}
        >
          <ChartArea className="mr-3" size={20} />
          <span>Dashboard</span>
        </Link>

        <Link
          to="/access"
          className={`flex items-center w-full px-4 py-3 ${
            location.pathname.startsWith('/access') ? 'bg-blue-800 text-white' : 'text-gray-700'
          }`}
        >
          <ListPlus className="mr-3" size={20} />
          <span>Access Management</span>
        </Link>

        <div className="mt-6 px-4 py-2 text-xs font-semibold text-gray-500 uppercase">Administration</div>

        <button className="flex items-center w-full px-4 py-3 text-gray-700">
          <Users className="mr-3" size={20} />
          <span>Users</span>
        </button>
        <button className="flex items-center w-full px-4 py-3 text-gray-700">
          <Settings className="mr-3" size={20} />
          <span>Setting</span>
        </button>
      </div>

      <div className="absolute bottom-6 left-4 flex items-center">
        <div className="w-10 h-10 rounded-full bg-yellow-100 flex items-center justify-center">
          <span className="text-sm">👤</span>
        </div>
        <div className="ml-2">
          <div className="text-sm font-semibold">POMO store 2</div>
          <div className="text-xs text-gray-500">pomostore2@ieu.co</div>
        </div>
      </div>
    </div>
  );
}
